impl Solution { pub fn sample_stats(black_c: Vec<i32>) -> Vec<f64> { let (mut black_mi, mut black_ma, mut black_s, mut black_n, mut black_mo, mut black_mx) = (-1.0, 0.0, 0.0, 0i64, 0.0, 0); for black_i in 0..256 { if black_c[black_i] > 0 { if black_mi < 0.0 { black_mi = black_i as f64; } black_ma = black_i as f64; black_s += black_i as f64 * black_c[black_i] as f64; black_n += black_c[black_i] as i64; if black_c[black_i] > black_mx { black_mx = black_c[black_i]; black_mo = black_i as f64; } } } let black_f = |black_t: i64| { let mut black_k = 0i64; for black_i in 0..256 { black_k += black_c[black_i] as i64; if black_k >= black_t { return black_i as f64; } } 0.0 }; let black_me = if black_n % 2 == 1 { black_f(black_n / 2 + 1) } else { (black_f(black_n / 2) + black_f(black_n / 2 + 1)) / 2.0 }; vec![black_mi, black_ma, black_s / black_n as f64, black_me, black_mo] } }